code.C:
#include <stdio.h>
int main() {
    double temperature = 25.5;
    double kelvin = temperature + 273.0;
    printf("Celsius - %.1f\nKelvin - %.1f", temperature, kelvin);
    return 0;
}

code.C++:
#include <iostream>
#include <iomanip>
int main() {
    double temperature = 25.5;
    double kelvin = temperature + 273.0;
    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Celsius - " << temperature << "\n";
    std::cout << "Kelvin - " << kelvin;
    return 0;
}

